#include <iostream>
#include <vector>

using namespace std;

void mergeIntervals(vector<pair<int, int>>& intervals1, vector<pair<int, int>>& intervals2, int& result) {
    // Read input
    int n = intervals1.size(), m = intervals2.size();

    // Sort intervals by end points
    sort(intervals1.begin(), intervals1.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
        return a.second < b.second;
    });
    sort(intervals2.begin(), intervals2.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
        return a.second < b.second;
    });

    // Merge non-conflicting pairs of intervals
    int i = 0, j = 0;
    while (i < n && j < m) {
        if (intervals1[i].second < intervals2[j].second) {
            // Append interval without conflict
            result += 1;
            cout << intervals1[i].first << ' ' << intervals1[i].second << '
';
            i++;
        } else if (intervals2[j].second < intervals1[i].second) {
            // Append interval without conflict
            result += 1;
            cout << intervals2[j].first << ' ' << intervals2[j].second << '
';
            j++;
        } else {
            // Merging conflicting intervals
            int merged_start = min(intervals1[i].first, intervals2[j].first);
            int merged_end = max(intervals1[i].second, intervals2[j].second);
            result += 1;
            cout << merged_start << ' ' << merged_end << '
';
            i++;
            j++;
        }
    }

    // Append any remaining intervals
    while (i < n) {
        result += 1;
        cout << intervals1[i].first << ' ' << intervals1[i].second << '
';
        i++;
    }
    while (j < m) {
        result += 1;
        cout << intervals2[j].first << ' ' << intervals2[j].second << '
';
        j++;
    }
}
